class CoapMessage:
    def __init__(self):
        self.version = 1
        self.type = 0
        self.token_length = 0
        self.code = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''
    
    def parse(self, data):
        if len(data) < 4:
            return False
        
        first_byte = data[0]
        self.version = (first_byte >> 6) & 0x03
        self.type = (first_byte >> 4) & 0x03
        self.token_length = first_byte & 0x0F
        
        self.code = data[1]
        self.message_id = struct.unpack('!H', data[2:4])[0]
        
        pos = 4
        if self.token_length > 0:
            self.token = data[pos:pos + self.token_length]
            pos += self.token_length
        
        self.options = []
        option_number = 0
        while pos < len(data):
            if data[pos] == 0xFF:
                pos += 1
                self.payload = data[pos:]
                break
            
            option_delta = (data[pos] >> 4) & 0x0F
            option_length = data[pos] & 0x0F
            pos += 1
            
            if option_delta == 13:
                option_delta = data[pos] + 13
                pos += 1
            elif option_delta == 14:
                option_delta = struct.unpack('!H', data[pos:pos+2])[0] + 269
                pos += 2
            
            if option_length == 13:
                option_length = data[pos] + 13
                pos += 1
            elif option_length == 14:
                option_length = struct.unpack('!H', data[pos:pos+2])[0] + 269
                pos += 2
            
            option_number += option_delta
            option_value = data[pos:pos + option_length]
            pos += option_length
            
            self.options.append((option_number, option_value))
        
        return True
    
    def build(self):
        first_byte = (self.version << 6) | (self.type << 4) | self.token_length
        header = struct.pack('!BBH', first_byte, self.code, self.message_id)
        
        data = header + self.token
        
        prev_option = 0
        for option_num, option_val in sorted(self.options):
            delta = option_num - prev_option
            length = len(option_val)
            
            delta_ext = b''
            if delta < 13:
                delta_nibble = delta
            elif delta < 269:
                delta_nibble = 13
                delta_ext = struct.pack('!B', delta - 13)
            else:
                delta_nibble = 14
                delta_ext = struct.pack('!H', delta - 269)
            
            length_ext = b''
            if length < 13:
                length_nibble = length
            elif length < 269:
                length_nibble = 13
                length_ext = struct.pack('!B', length - 13)
            else:
                length_nibble = 14
                length_ext = struct.pack('!H', length - 269)
            
            option_header = struct.pack('!B', (delta_nibble << 4) | length_nibble)
            data += option_header + delta_ext + length_ext + option_val
            prev_option = option_num
        
        if self.payload:
            data += b'\xFF' + self.payload
        
        return data
    
    def get_uri_path(self):
        path_parts = []
        for opt_num, opt_val in self.options:
            if opt_num == 11:
                path_parts.append(opt_val.decode('utf-8'))
        return '/' + '/'.join(path_parts) if path_parts else '/'

class CoapServer:
    TYPE_CON = 0
    TYPE_NON = 1
    TYPE_ACK = 2
    TYPE_RST = 3
    
    CODE_GET = 1
    CODE_POST = 2
    CODE_PUT = 3
    CODE_DELETE = 4
    
    CODE_CREATED = 65
    CODE_DELETED = 66
    CODE_VALID = 67
    CODE_CHANGED = 68
    CODE_CONTENT = 69
    CODE_BAD_REQUEST = 128
    CODE_NOT_FOUND = 132
    CODE_METHOD_NOT_ALLOWED = 133
    CODE_INTERNAL_ERROR = 160
    
    CONTENT_FORMAT_TEXT = 0
    CONTENT_FORMAT_JSON = 50
    
    def __init__(self, port=5683):
        self.port = port
        self.sock = None
        self.resources = {}
        self.temp_sensor = None
        self.light_pin = None
        
    def setup_hardware(self):
        try:
            self.temp_sensor = ADC(Pin(34))
            self.temp_sensor.atten(ADC.ATTN_11DB)
        except:
            pass
        
        try:
            self.light_pin = Pin(2, Pin.OUT)
            self.light_pin.value(0)
        except:
            pass
    
    def add_resource(self, path, get_handler=None, put_handler=None):
        self.resources[path] = {
            'get': get_handler,
            'put': put_handler
        }
    
    def read_temperature(self):
        if self.temp_sensor:
            try:
                raw = self.temp_sensor.read()
                voltage = raw / 4095.0 * 3.3
                temp = (voltage - 0.5) * 100
                return {"temperature": round(temp, 2), "unit": "C"}
            except:
                return {"temperature": 25.0, "unit": "C"}
        return {"temperature": 25.0, "unit": "C"}
    
    def get_light_state(self):
        if self.light_pin:
            return {"state": "on" if self.light_pin.value() else "off"}
        return {"state": "off"}
    
    def set_light_state(self, payload):
        if self.light_pin:
            try:
                data = json.loads(payload.decode('utf-8'))
                state = data.get('state', 'off')
                self.light_pin.value(1 if state == 'on' else 0)
                return True
            except:
                return False
        return False
    
    def handle_get_temp(self, request):
        temp_data = self.read_temperature()
        return json.dumps(temp_data).encode('utf-8')
    
    def handle_get_light(self, request):
        light_data = self.get_light_state()
        return json.dumps(light_data).encode('utf-8')
    
    def handle_put_light(self, request):
        if self.set_light_state(request.payload):
            return json.dumps(self.get_light_state()).encode('utf-8')
        return None
    
    def create_response(self, request, code, payload=b'', content_format=None):
        response = CoapMessage()
        response.version = 1
        response.type = self.TYPE_ACK if request.type == self.TYPE_CON else self.TYPE_NON
        response.code = code
        response.message_id = request.message_id
        response.token = request.token
        response.token_length = len(response.token)
        
        if content_format is not None:
            response.options.append((12, struct.pack('!B', content_format)))
        
        response.payload = payload
        return response
    
    def handle_request(self, request, addr):
        uri_path = request.get_uri_path()
        
        if uri_path not in self.resources:
            return self.create_response(request, self.CODE_NOT_FOUND)
        
        resource = self.resources[uri_path]
        
        if request.code == self.CODE_GET:
            if resource['get']:
                try:
                    payload = resource['get'](request)
                    return self.create_response(request, self.CODE_CONTENT, payload, self.CONTENT_FORMAT_JSON)
                except Exception as e:
                    print("GET error:", e)
                    return self.create_response(request, self.CODE_INTERNAL_ERROR)
            else:
                return self.create_response(request, self.CODE_METHOD_NOT_ALLOWED)
        
        elif request.code == self.CODE_PUT:
            if resource['put']:
                try:
                    payload = resource['put'](request)
                    if payload is not None:
                        return self.create_response(request, self.CODE_CHANGED, payload, self.CONTENT_FORMAT_JSON)
                    else:
                        return self.create_response(request, self.CODE_BAD_REQUEST)
                except Exception as e:
                    print("PUT error:", e)
                    return self.create_response(request, self.CODE_INTERNAL_ERROR)
            else:
                return self.create_response(request, self.CODE_METHOD_NOT_ALLOWED)
        
        return self.create_response(request, self.CODE_METHOD_NOT_ALLOWED)
    
    def start(self):
        self.setup_hardware()
        
        self.add_resource('/sensors/temp', get_handler=self.handle_get_temp)
        self.add_resource('/actuators/light', 
                         get_handler=self.handle_get_light,
                         put_handler=self.handle_put_light)
        
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind(('0.0.0.0', self.port))
        self.sock.setblocking(False)
        
        print(f"CoAP server started on port {self.port}")
        print("Available resources:")
        for path in self.resources:
            print(f"  {path}")
        
        while True:
            try:
                data, addr = self.sock.recvfrom(1024)
                
                request = CoapMessage()
                if request.parse(data):
                    response = self.handle_request(request, addr)
                    if response:
                        self.sock.sendto(response.build(), addr)
                
            except OSError:
                time.sleep(0.01)
            except Exception as e:
                print("Error:", e)
                time.sleep(0.01)

def main():
    server = CoapServer()
